const extractRegisterPolicyError = (err) => {
  const response = err?.response?.data || {};
  const error = response.error || 'Registration failed. Please check server policies and credentials.';
  const policy = response.policy || null;
  return { error, policy };
};

function PolicyNotice({ policy }) {
  if (!policy) return null;
  return (
    <div className="policy-block">
      <div className="policy-title">Policy guidance</div>
      <div className="policy-description">{policy.description}</div>
      {policy.allowedCreators && (
        <div className="policy-detail">Allowed creators: {policy.allowedCreators.join(', ')}</div>
      )}
    </div>
  );
}

function CreateSchools({ state, setState }) {
