  const handleSubmit = async (event) => {
    event.preventDefault();
    const form = event.target;
    const teacher = state.teachers?.find(t => t.employeeId === form.studentTeacher.value || t.email === form.studentTeacher.value);
    const studentUser = {
      email: form.studentEmail.value,
      password: form.studentPassword.value,
      role: 'Student'
    };
    const studentRecord = {
      studentId: form.studentId.value,
      admissionNumber: form.studentAdmissionNumber.value,
      name: form.studentName.value,
      email: form.studentEmail.value,
      grade: form.studentGrade.value,
      section: form.studentSection.value,
      teacher: teacher ? { id: teacher.employeeId, name: teacher.name, email: teacher.email } : null,
      parent: {
        name: form.studentParentName.value,
        contact: form.studentParentContact.value,
        email: form.studentParentEmail.value
      },
      attendance: { present: 0, absent: 0, late: 0 },
      marks: {},
      status: 'Active'
    };

    try {
      const response = await axios.post('/api/auth/register', studentUser);
      const studentResponse = await axios.post('/api/students', studentRecord);
      const savedStudent = studentResponse.data;
      setState(prev => ({
        ...prev,
        students: [...prev.students, savedStudent],
        notifications: [{ id: Date.now(), message: `[Student created] ${savedStudent.name} created with student ID ${savedStudent.studentId}.`, channels: ['Admin', 'Student'], time: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }) }, ...prev.notifications]
