function MarkAttendance({ state, setState }) {
  const selectedStudents = state.students.filter(student => student.grade === '5');
  const [attendanceSelections, setAttendanceSelections] = useState({});
  const [saveSuccess, setSaveSuccess] = useState('');

  useEffect(() => {
    setAttendanceSelections(selectedStudents.reduce((map, student) => {
      map[student.admissionNumber] = 'Present';
      return map;
    }, {}));
  }, [selectedStudents]);

  const handleStatusChange = (studentId, status) => {
    setAttendanceSelections(prev => ({ ...prev, [studentId]: status }));
  };

  const handleSubmit = (event) => {
    event.preventDefault();
    const updates = selectedStudents.map(student => {
      const status = attendanceSelections[student.admissionNumber] || 'Present';
      return {
        ...student,
        attendance: {
          ...student.attendance,
          present: student.attendance.present + (status === 'Present' ? 1 : 0),
          absent: student.attendance.absent + (status === 'Absent' ? 1 : 0),
          late: student.attendance.late + (status === 'Late' ? 1 : 0)
        }
      };
    });

    setState(prev => ({
      ...prev,
      students: prev.students.map(student => updates.find(update => update.admissionNumber === student.admissionNumber) || student),
      notifications: [{
        id: Date.now(),
        message: '[Teacher marked attendance] Attendance updated for class 5A.',
        channels: ['Vice Principal'],
        time: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })
      }, ...prev.notifications]
    }));

    setSaveSuccess('Attendance saved successfully.');
    window.setTimeout(() => setSaveSuccess(''), 4000);
  };

  return panelWrapper('Mark Attendance', 'Renders a student grid workspace for present, absent, or late status.', (
    <form className="table-card" onSubmit={handleSubmit}>
      <table>
        <thead><tr><th>Admission No.</th><th>Student</th><th>Present</th><th>Absent</th><th>Late</th></tr></thead>
        <tbody>{selectedStudents.map(student => (
          <tr key={student.admissionNumber}>
            <td>{student.admissionNumber}</td>
            <td>{student.name}</td>
            <td><button type="button" className={`attendance-button ${attendanceSelections[student.admissionNumber] === 'Present' ? 'active' : ''}`} onClick={() => handleStatusChange(student.admissionNumber, 'Present')}>Present</button></td>
            <td><button type="button" className={`attendance-button ${attendanceSelections[student.admissionNumber] === 'Absent' ? 'active' : ''}`} onClick={() => handleStatusChange(student.admissionNumber, 'Absent')}>Absent</button></td>
            <td><button type="button" className={`attendance-button ${attendanceSelections[student.admissionNumber] === 'Late' ? 'active' : ''}`} onClick={() => handleStatusChange(student.admissionNumber, 'Late')}>Late</button></td>
          </tr>
        ))}</tbody>
      </table>
      <div className="form-actions"><button type="submit">Save Attendance</button></div>
      {saveSuccess && <div className="success-text">{saveSuccess}</div>}
    </form>
  ));
}

