              <td>{fee.dueDate}</td>
              <td>{fee.status}</td>
              <td><button type="button" onClick={() => setSelectedFeeId(fee.id)}>Select</button></td>
            </tr>
          ))}</tbody>
        </table>
      </div>
      {selectedFee ? (
        <div className="panel-card">
          <h3>Pay ₹{selectedFee.amount.toLocaleString()} for {selectedFee.student}</h3>
          <StripeCheckoutForm fee={selectedFee} onSuccess={handleSuccess} user={user} />
        </div>
      ) : (
        <div className="empty-state">No pending student fees available for payment.</div>
      )}
    </div>
  ));
}

function PayChildFees({ state, setState, user }) {
  const pendingFees = state.financials.fees.filter(fee => fee.status !== 'Paid');
  const [selectedFeeId, setSelectedFeeId] = useState(pendingFees[0]?.id || '');
  const selectedFee = pendingFees.find(fee => fee.id === selectedFeeId);

  const handleSuccess = (feeId) => {
    setState(prev => ({
      ...prev,
      financials: {
        ...prev.financials,
        fees: prev.financials.fees.map(item => item.id === feeId ? { ...item, status: 'Paid' } : item)
      },
      notifications: [{
        id: Date.now(),
        message: `[Fee payment successful] Payment processed for ${selectedFee?.student}.`,
        channels: ['Accountant', 'Parent'],
        time: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })
      }, ...prev.notifications]
    }));
  };

  return panelWrapper('Pay Fees', 'Parent checkout terminal for tuition and exam fee payments via Stripe secure card processing.', (
    <div className="grid-gap">
      <div className="table-card">
        <table>
          <thead><tr><th>Child</th><th>Fee Type</th><th>Amount</th><th>Status</th><th>Action</th></tr></thead>
          <tbody>{state.financials.fees.map(fee => (
            <tr key={fee.id} className={fee.id === selectedFeeId ? 'selected-row' : ''}>
              <td>{fee.student}</td>
              <td>{fee.type}</td>
              <td>₹{fee.amount.toLocaleString()}</td>
              <td>{fee.status}</td>
              <td><button type="button" disabled={fee.status === 'Paid'} onClick={() => setSelectedFeeId(fee.id)}>{fee.status === 'Paid' ? 'Paid' : 'Select'}</button></td>
            </tr>
          ))}</tbody>
        </table>
      </div>
      {selectedFee ? (
        <div className="panel-card">
          <h3>Pay ₹{selectedFee.amount.toLocaleString()} for {selectedFee.student}</h3>
          <StripeCheckoutForm fee={selectedFee} onSuccess={handleSuccess} user={user} />
        </div>
      ) : (
        <div className="empty-state">Select a child fee to pay securely.</div>
      )}
    </div>
  ));
}

function StripeCheckoutForm({ fee, onSuccess, user }) {
  const [stripePromise, setStripePromise] = useState(null);
  const [stripeError, setStripeError] = useState('');

  useEffect(() => {
    let isMounted = true;
    import('@stripe/stripe-js')
      .then(({ loadStripe }) => loadStripe(stripePublishableKey))
      .then((stripeInstance) => {
        if (!isMounted) return;
        if (!stripeInstance) {
          setStripeError('Unable to load Stripe. Please try again later.');
          return;
        }
        setStripePromise(stripeInstance);
      })
      .catch((error) => {
        console.error('Stripe load error:', error);
        if (isMounted) setStripeError('Unable to load Stripe. Please try again later.');
      });
    return () => { isMounted = false; };
  }, []);

  if (stripeError) {
    return <div className="info-text">{stripeError}</div>;
  }

  if (!stripePromise) {
    return <div className="info-text">Loading payment form…</div>;
  }

  return (
    <Elements stripe={stripePromise}>
      <StripeCheckoutFormInner fee={fee} onSuccess={onSuccess} user={user} />
    </Elements>
  );
}

function StripeCheckoutFormInner({ fee, onSuccess, user }) {
  const stripe = useStripe();
  const elements = useElements();
  const [message, setMessage] = useState('');
  const [isProcessing, setIsProcessing] = useState(false);

  const handleSubmit = async (event) => {
    event.preventDefault();
    if (!stripe || !elements) {
      setMessage('Stripe is not ready yet.');
      return;
    }
    setMessage('');
    setIsProcessing(true);

    try {
      const intentResponse = await axios.post('/api/payments/create-payment-intent', {
        amount: fee.amount,
        currency: 'usd',
        description: `${fee.type} payment for ${fee.student}`,
        studentEmail: user?.email || 'anonymous@school.edu'
      }, {
        headers: {
          Authorization: `Bearer ${user?.token}`
        }
      });

      const clientSecret = intentResponse.data.clientSecret;
      const cardElement = elements.getElement(CardElement);
      if (!cardElement) throw new Error('Card element not found.');

      const { error, paymentIntent } = await stripe.confirmCardPayment(clientSecret, {
        payment_method: {
          card: cardElement,
          billing_details: {
            email: user?.email,
            name: user?.email
          }
        }
      });

      if (error) {
        setMessage(error.message || 'Payment failed.');
      } else if (paymentIntent?.status === 'succeeded') {
        onSuccess(fee.id);
        setMessage('Payment succeeded. Thank you!');
      } else {
        setMessage('Payment did not complete.');
      }
    } catch (err) {
      console.error('Payment error', err);
      setMessage(err.response?.data?.message || err.message || 'Unable to process payment.');
    }

    setIsProcessing(false);
  };

  return (
    <form className="grid-form" onSubmit={handleSubmit}>
      <label>
        Card details
        <div className="card-element-container"><CardElement options={{ style: { base: { fontSize: '16px', color: '#32325d', '::placeholder': { color: '#a0aec0' } }, invalid: { color: '#fa755a' } } }} /></div>
      </label>
      <div className="form-actions">
        <button type="submit" disabled={!stripe || isProcessing}>{isProcessing ? 'Processing…' : `Pay ₹${fee.amount.toLocaleString()}`}</button>
      </div>
      {message && <div className="info-text">{message}</div>}
    </form>
  );
}

